selector_to_html = {"a[href=\"save_as.html#terminal-usage-cli\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1.1. </span>Terminal usage (CLI)<a class=\"headerlink\" href=\"#terminal-usage-cli\" title=\"Link to this heading\">#</a></h2><p>When no <code class=\"docutils literal notranslate\"><span class=\"pre\">--save</span></code> path is given, only metadata is printed.</p>", "a[href=\"run_gui.html#jupyter-ipython\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.1. </span>Jupyter / IPython<a class=\"headerlink\" href=\"#jupyter-ipython\" title=\"Link to this heading\">#</a></h2><p>Returns a <code class=\"xref py py-class docutils literal notranslate\"><span class=\"pre\">fastplotlib.ImageWidget</span></code>:</p>", "a[href=\"#function-usage\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Function Usage<a class=\"headerlink\" href=\"#function-usage\" title=\"Link to this heading\">#</a></h1><p>Examples of some common function use cases.</p>", "a[href=\"save_mp4.html#load-data\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3.1. </span>Load Data<a class=\"headerlink\" href=\"#load-data\" title=\"Link to this heading\">#</a></h2>", "a[href=\"run_gui.html#python-script-non-jupyter\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2.2. </span>Python script (non-Jupyter)<a class=\"headerlink\" href=\"#python-script-non-jupyter\" title=\"Link to this heading\">#</a></h2><p>If run from a script without data_in, and Qt is installed, a file dialog will prompt for input.</p>", "a[href=\"save_mp4.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3. </span><code class=\"docutils literal notranslate\"><span class=\"pre\">save_mp4</span></code><a class=\"headerlink\" href=\"#save-mp4\" title=\"Link to this heading\">#</a></h1><p><a class=\"reference internal\" href=\"../api/visualization.html#mbo_utilities.save_mp4\" title=\"mbo_utilities.save_mp4\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">mbo_utilities.save_mp4()</span></code></a></p><p><code class=\"docutils literal notranslate\"><span class=\"pre\">save_mp4</span></code> converts a 3D numpy array or TIFF stack (<code class=\"docutils literal notranslate\"><span class=\"pre\">[T,</span> <span class=\"pre\">Y,</span> <span class=\"pre\">X]</span></code>) into an <code class=\"docutils literal notranslate\"><span class=\"pre\">.mp4</span></code> video.</p>", "a[href=\"save_as.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1. </span><code class=\"docutils literal notranslate\"><span class=\"pre\">save_as</span></code><a class=\"headerlink\" href=\"#save-as\" title=\"Link to this heading\">#</a></h1><p><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">mbo_utilities.save_as()</span></code> is a convenience function for exporting common data formats processed from MBO datasets.</p><p>It can save <strong>ScanImage tiffs</strong> or <strong>ScanMultiROIReordered arrays</strong> into:</p>", "a[href=\"save_mp4.html#parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3.3. </span>Parameters<a class=\"headerlink\" href=\"#parameters\" title=\"Link to this heading\">#</a></h2>", "a[href=\"save_mp4.html#example-usage\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3.2. </span>Example Usage<a class=\"headerlink\" href=\"#example-usage\" title=\"Link to this heading\">#</a></h2>", "a[href=\"run_gui.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2. </span><code class=\"docutils literal notranslate\"><span class=\"pre\">run_gui</span></code><a class=\"headerlink\" href=\"#run-gui\" title=\"Link to this heading\">#</a></h1><p><a class=\"reference internal\" href=\"../api/visualization.html#mbo_utilities.run_gui\" title=\"mbo_utilities.run_gui\"><code class=\"xref py py-func docutils literal notranslate\"><span class=\"pre\">mbo_utilities.run_gui()</span></code></a> is a convenience function for viewing common data formats used in processing MBO datasets, usable from the terminal, jupyter-lab or a callable from a python script.</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
